import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { motion } from 'framer-motion';
import { getMediaUrl } from '../../services/api';
import {
  CardContainer,
  CardImage,
  CardContent,
  CardTitle,
  CardDescription,
  CardPrice,
  CardFooter
} from './MenuCard.styles';

const MenuCard = ({ item, type, index = 0 }) => {
  const { t } = useTranslation();
  const [imageLoaded, setImageLoaded] = useState(false);
  const [isHovered, setIsHovered] = useState(false);

  const formatPrice = (price) => {
    if (!price) return t('menu.priceOnRequest', 'Price on request');
    return new Intl.NumberFormat('uz-UZ').format(price);
  };

  // Get proper image URL
  const imageUrl = getMediaUrl(item.photo);

  // For beverages, don't show detailed descriptions - keep it simple
  const shouldShowDescription = type === 'food' && item.ingredients;

  return (
    <CardContainer
      as={motion.div}
      initial={{ opacity: 0, y: 30, scale: 0.95 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      transition={{ 
        duration: 0.5, 
        delay: index * 0.1,
        ease: [0.25, 0.46, 0.45, 0.94]
      }}
      whileHover={{ 
        y: -8, 
        scale: 1.02,
        transition: { duration: 0.3, ease: "easeOut" }
      }}
      onHoverStart={() => setIsHovered(true)}
      onHoverEnd={() => setIsHovered(false)}
    >
      <CardImage>
        <motion.img 
          src={imageUrl || '/images/placeholder-menu.svg'} 
          alt={item.name}
          style={{
            transform: isHovered ? 'scale(1.1)' : 'scale(1)',
            transition: 'transform 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94)'
          }}
          onLoad={() => setImageLoaded(true)}
          onError={(e) => {
            e.target.src = '/images/placeholder-menu.svg';
            setImageLoaded(true);
          }}
        />

        {/* Elegant price overlay */}
        <motion.div
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: 0.3 }}
          style={{
            position: 'absolute',
            bottom: '16px',
            left: '16px',
            background: 'linear-gradient(135deg, rgba(139, 69, 19, 0.95), rgba(160, 82, 45, 0.95))',
            backdropFilter: 'blur(10px)',
            color: 'white',
            padding: '8px 16px',
            borderRadius: '16px',
            fontSize: '0.875rem',
            fontWeight: '700',
            boxShadow: '0 4px 16px rgba(139, 69, 19, 0.4)',
            border: '1px solid rgba(255,255,255,0.2)'
          }}
        >
          {formatPrice(item.price)} {item.price ? t('menu.currency', 'сум') : ''}
        </motion.div>
      </CardImage>

      <CardContent>
        <CardTitle>{item.name}</CardTitle>

        {/* Only show description for food items, keep beverages simple */}
        {shouldShowDescription && (
          <CardDescription>
            {item.ingredients}
          </CardDescription>
        )}

        {/* Minimal nutrition info for food items only */}
        {type === 'food' && item.calories && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
            style={{
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              marginTop: '12px',
              padding: '8px 16px',
              backgroundColor: 'rgba(139, 69, 19, 0.05)',
              borderRadius: '12px',
              border: '1px solid rgba(139, 69, 19, 0.1)'
            }}
          >
            <span style={{ 
              fontSize: '0.75rem', 
              color: '#8B4513', 
              fontWeight: '600',
              marginRight: '8px'
            }}>
              Ккал:
            </span>
            <span style={{ 
              fontSize: '0.875rem', 
              fontWeight: '700', 
              color: '#1f2937' 
            }}>
              {item.calories}
            </span>
          </motion.div>
        )}

        <CardFooter>
          {/* Category badge for beverages */}
          {type === 'beverages' && item.type_display && (
            <motion.div
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ delay: 0.5 }}
              style={{
                padding: '4px 12px',
                backgroundColor: 'rgba(139, 69, 19, 0.1)',
                color: '#8B4513',
                borderRadius: '8px',
                fontSize: '0.75rem',
                fontWeight: '600',
                textTransform: 'capitalize'
              }}
            >
              {item.type_display}
            </motion.div>
          )}
        </CardFooter>
      </CardContent>

      {/* Hover indicator */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: isHovered ? 1 : 0 }}
        style={{
          position: 'absolute',
          top: '16px',
          right: '16px',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          backgroundColor: '#8B4513',
          boxShadow: '0 0 12px rgba(139, 69, 19, 0.6)'
        }}
      />
    </CardContainer>
  );
};

export default MenuCard;
